from langchain_core.messages import AIMessageChunk

def stream_agent(query: str):
    """Stream agent output token by token."""
    for chunk in executor.stream({"input": query}):
        if "output" in chunk:
            # Final complete output
            print(f"\nFinal: {chunk['output']}")
        elif "actions" in chunk:
            for action in chunk["actions"]:
                print(f"[tool] {action.tool}({action.tool_input})")
        elif "steps" in chunk:
            for step in chunk["steps"]:
                print(f"[result] {step.observation[:80]}")

stream_agent("Calculate 99 * 99 and count the words in 'the quick brown fox'.")
# [tool] calculate({'expression': '99 * 99'})
# [result] 9801
# [tool] word_count({'text': 'the quick brown fox'})
# [result] 4 words
# Final: 99 * 99 = 9801. 'The quick brown fox' contains 4 words.

from pydantic import BaseModel, Field
from langchain_core.tools import tool

class WeatherInput(BaseModel):
    city: str = Field(description="The city to get weather for")
    unit: str = Field(
        default="celsius",
        description="Temperature unit: 'celsius' or 'fahrenheit'",
    )

@tool("get_weather", args_schema=WeatherInput)
def get_weather(city: str, unit: str = "celsius") -> str:
    """Get the current weather for a given city."""
    # In production: call a real weather API
    temp = 22 if unit == "celsius" else 72
    return f"Weather in {city}: {temp}°{'C' if unit == 'celsius' else 'F'}, partly cloudy."

class SearchInput(BaseModel):
    query: str = Field(description="The search query")
    num_results: int = Field(default=3, description="Number of results to return (1-10)")

@tool("web_search_structured", args_schema=SearchInput)
def web_search_structured(query: str, num_results: int = 3) -> str:
    """Search the web for information. Returns top results."""
    # In production: call a real search API (SerpAPI, DuckDuckGo)
    return f"Top {num_results} results for '{query}': [result1, result2, ...]"

