from langchain.callbacks.base import BaseCallbackHandler
from typing import Any

class AgentObserver(BaseCallbackHandler):
    """Logs tool calls and LLM invocations for observability."""

    def __init__(self):
        self.tool_calls: list[dict] = []
        self.llm_calls: int = 0

    def on_llm_start(self, serialized: dict, prompts: list[str], **kwargs: Any):
        self.llm_calls += 1

    def on_tool_start(self, serialized: dict, input_str: str, **kwargs: Any):
        self.tool_calls.append({
            "tool": serialized.get("name"),
            "input": input_str[:200],
        })

    def on_tool_error(self, error: Exception, **kwargs: Any):
        print(f"[Tool error] {error}")

    def on_agent_finish(self, finish, **kwargs: Any):
        print(f"[Agent done] LLM calls: {self.llm_calls}, Tool calls: {len(self.tool_calls)}")

    def summary(self) -> dict:
        return {
            "llm_calls": self.llm_calls,
            "tool_calls": self.tool_calls,
        }

observer = AgentObserver()

observed_executor = AgentExecutor(
